4. Both": "Pessimistic", "Transactions": "2", "Triggering Description": "The following simple test case for MTR framework shows that the problem is repeatable without binary log enabled and without additional changes to code to adjust the read-set bitmap:

--enable_connect_log
create table t(a int, b int) engine=innodb;
insert into t values (1, 0), (2, 1), (3, 2);

set transaction isolation level repeatable read;
begin;
select * from t;

connect (addconroot1, localhost, root,,);
begin;
update t set a = 10 where b = 1;
commit;

connection default;
select * from t;
update t set a = 10 where a;
select * from t;
# The above returns (which is wrong!)
# a b
# 10 0
# 2 1
# 10 2

commit;

In fact with this test case the problem is repeatable even in 5.5 tree (for 5.5.65-git to be exact).", "Unnamed: 10": "S2 (Serious)", "Unnamed: 16": "-", "Unnamed: 17": "-", "Unnamed: 18": "-", "Unnamed: 19": "-", "Unnamed: 21": "explicit", "Unnamed: 22": "6", "Unnamed: 23": "explicit", "Unnamed: 24": "3", "Unnamed: 25": "-", "Unnamed: 26": "-", "Unnamed: 27": "-", "Unnamed: 28": "-", "Unnamed: 29": "-", "Unnamed: 30": "-", "Unnamed: 32": "-", "Unnamed: 33": "-", "Unnamed: 34": "-", "Unnamed: 35": "Yes", "Unnamed: 36": "-", "Unnamed: 37": "Yes", "Unnamed: 38": "-", "Unnamed: 39": "-", "Unnamed: 4": "--enable_connect_log
