CREATE TABLE t1 (a INT) ENGINE=InnoDB;

START TRANSACTION;
SELECT * FROM t1;

--connect (con1,localhost,root,,test)
CREATE SEQUENCE s1 ENGINE=InnoDB;
FLUSH TABLES;
--disconnect con1

--connection default
--error ER_TABLE_DEF_CHANGED,ER_NO_SUCH_TABLE
